/**
 * Look up Kubescape control metadata by control ID.
 * Returns undefined for unknown controls.
 */
export function getKubescapeControlMeta(controlId: string): KubescapeControlMeta | undefined {
  return KUBESCAPE_CONTROL_META[controlId];
}
